const CustomTabButton = (props: any) => {
    const handlePress = () => {
        if (Platform.OS === 'ios') {
            Haptics.selectionAsync();
        }
        // Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
        if (props.onPress) {
            props.onPress();
        }
    };

    return (
        <TouchableOpacity
            {...props}
            onPress={handlePress}
            activeOpacity={1}
            style={[props.style, { overflow: 'hidden' }]}
            android_ripple={null}
        />
    );
};

function TabsLayout() {
    const insets = useSafeAreaInsets();
    return (
        <>
            <Tabs
                initialRouteName="(home)"
                screenOptions={{
                    headerShown: false,
                    tabBarStyle: {
                        ...styles.tabBar,
                        paddingBottom: insets.bottom,
                        height: 70 + insets.bottom,
                        backgroundColor: '#FFFFFF',
                        borderTopWidth: 0,
                        borderTopColor: 'transparent',
                        elevation: 8,
                        shadowOpacity: 0.15,
                        shadowColor: '#000000',
                        shadowOffset: { width: 0, height: -8 },
                        shadowRadius: 12,
                    },
                    tabBarItemStyle: {
                        backgroundColor: 'transparent',
                    },
                    tabBarLabelStyle: styles.titleStyle,
                    tabBarIconStyle: styles.icon,
                    tabBarActiveTintColor: '#A20538',
                    tabBarInactiveTintColor: '#808080',
                    tabBarButton: (props) => <CustomTabButton {...props} />,
                }}
            >
                <Tabs.Screen
                    name="(home)"
                    options={{
                        tabBarLabel: "Home",
                        title: "Home",
                        tabBarIcon: ({ focused }) => (
                            <HomeIcon isFocused={focused} />
                        ),
                        tabBarShowLabel: true,
                    }}
                />
                <Tabs.Screen
                    name="menu"
                    options={{
                        tabBarLabel: "Menu",
                        title: "Menu",
                        tabBarIcon: ({ focused }) => (
                            <MenuIcon isFocused={focused} />
                        ),
                        tabBarShowLabel: true,
                    }}
                />
                <Tabs.Screen
                    name="order-later"
                    options={{
                        tabBarLabel: "Orders Later",
                        title: "Orders Later",
                        tabBarIcon: ({ focused }) => (
                            <OrdersIcon isFocused={focused} />
                        ),
                        tabBarShowLabel: true,
                    }}
                />
                <Tabs.Screen
                    name="dine-in"
                    options={{
                        tabBarLabel: "Dine-In",
                        title: "Dine-In",
                        tabBarIcon: ({ focused }) => (
                            <DineInIcon isFocused={focused} />
                        ),
                        tabBarShowLabel: true,
                    }}
                />
            </Tabs>
        </>
    );
}

export default TabsLayout;

const styles = StyleSheet.create({
    titleStyle: {
        letterSpacing: 0.02,
        width: '100%',
        marginBottom: Platform.OS === 'android' ? 10 : 2,
    },
    icon: {
        marginTop: 10,
    },
    tabBar: {
        height: 60,
    }
});